---@class LUISkillCtrl
local LUISkillCtrl = LxClass("LUISkillCtrl", nil)

------------------------------------------------------------------
---@type LUIEffectObject
local LUIEffectObject = LXImport(".LUIEffectObject")
local LFightFade =  LXImport("LApp.gameplay.fight.View.LFightFade")

------------------------------------------------------------------
function LUISkillCtrl:LUISkillCtrl(wndClass)
	---@type LWnd
	self._wndClass = wndClass

	---@type LUIHeroObject
	self._uiHeroObj = nil

	---@type table<string,LUIEffectObject[]>
	self._uiPreLoadEffList = nil

	self._uiEffObjList = nil

	self._skillData = nil

	self._playEffList = nil

	self._parentTrans = nil

	self._sortBottom = 0
	self._sortUp = 3
	self._drawingSortAdd = 20
	self._fadeSortAdd = 19

	self._isPlaying = false
	self._isWait = false

	self._playMaxTime = 0
	self._startTime = 0
	self._scaleSize = 1

	self._pixelPreUnit = 100

	self._curTime = 0

	self._heroOffectPointList = {
		[1] = 0.06,
		[2] = 0.12,
		[3] = 0.18,
		[4] = 0.24,
		[5] = 0.30,
	}
end

function LUISkillCtrl:InitData(uiHeroObj, skillData, parentTrans, sortBottom, sortUp, scaleSize)
	self._uiHeroObj = uiHeroObj

	self._skillData = skillData
	self._playEffList = skillData:GetPlayEffList()

	self._playStateList = {}

	self._uiEffObjList = {}

	self._parentTrans = parentTrans
	self._sortBottom = sortBottom
	self._sortUp = sortUp
	self._scaleSize = scaleSize or 1

	self._pixelPreUnit = self._scaleSize

	self:InitPlayState()
end

function LUISkillCtrl:EnableSpeedUp(bEnable,val)
	self._bSpeedUp = bEnable
	self._speedUpVal = val
end

function LUISkillCtrl:GetUIEffectObject(effRes)
	if not self._uiPreLoadEffList then return nil end
	local tbl = self._uiPreLoadEffList[effRes]
	if not tbl then return nil end
	if #tbl == 0 then return nil end
	return table.remove(tbl)
end

function LUISkillCtrl:MakeEffect(ref)
	local dp = self:GetUIEffectObject(ref.effRes)
	if not dp then
		dp = self:CreateEffect(ref,nil,nil,ref.effType)
		dp:StartLoad()
	end
	return dp
end

function LUISkillCtrl:CreateEffect(ref, index, callFunc,effType)
	local sortBottom = self._sortBottom
	local sortUp = self._sortUp
	local parentTrans = self._parentTrans
	local wndClass = self._wndClass
	local scaleSize = self._scaleSize

	local dp = LUIEffectObject:New(wndClass)
	local sortIndex = 0
	local refId = ref.refId
	local uiHierarchy = 0
	local skillVfxRef = GameTable.SnakeSkillVfxRef[refId]
	if skillVfxRef then
		uiHierarchy = skillVfxRef.UiHierarchy
	end
	if uiHierarchy == 1 then
		sortIndex = sortBottom
	else
		sortIndex = sortUp
	end

	local resType = 1
	if effType == LSkillEffConst.PLAY_EFF_DRAWING then
		sortIndex = sortUp + self._drawingSortAdd
		resType = 2
	end


	dp:Create(parentTrans, ref.effRes, scaleSize, index, sortIndex, callFunc,true,resType)
	return dp
end

function LUISkillCtrl:GeneratePlayState(index, refId, startTime, playTime, endTime)
	local playState = {
		index = index,
		refId = refId,
		isPlay = true,
		startTime = startTime,
		playTime=playTime,
		endTime = endTime,
		isFinished = false,
		childFinished = false,
		childList = {} ,
		leftEffects = nil
	}
	return playState
end

function LUISkillCtrl:GenerateChildPlayState(effData, startTime, playTime, endTime)
	local playState = { effData = effData, isPlay = false, startTime = startTime, playTime = playTime, endTime = endTime, isFinished = false }
	return playState
end

function LUISkillCtrl:InitPlayState()
	local playStateList = {}
	self._playStateList = playStateList
	local speedVal = 1
	if self._bSpeedUp then
		speedVal = 1 / self._speedUpVal
	end
	for k, v in ipairs(self._playEffList) do
		local playState = self:GeneratePlayState(k, v.refId, v.delayTime * speedVal, v.playTime * speedVal, 0)
		playState.isPlay = false
		playStateList[k] = playState
	end
end

function LUISkillCtrl:PreLoadPlaySkill()
	self._isWait = true
	local preloadCount = 0
	local onPreloadSkillShow = function()
		if self._isDestroy then return end
		preloadCount = preloadCount - 1
		if preloadCount <= 0 then
			self:PlaySkill()
		end
	end

	local playList = self._playEffList or {}

	local preLoadObjList = {}
	self._uiPreLoadEffList = preLoadObjList

	for i,v in ipairs(playList) do
		local effType = v.effType
		if effType == LSkillEffConst.PLAY_EFF_SOUND or
				effType == LSkillEffConst.PLAY_EFF_EFFECT or
				effType == LSkillEffConst.PLAY_EFF_BULLET or
				effType == LSkillEffConst.PLAY_EFF_DRAWING
		then
			preloadCount = preloadCount + 1
		end
	end

	for i,v in ipairs(playList) do
		local effType = v.effType
		if effType == LSkillEffConst.PLAY_EFF_SOUND then
			gLGameAudio:LoadSound(v.effRes, onPreloadSkillShow)
		elseif effType == LSkillEffConst.PLAY_EFF_EFFECT or
				effType == LSkillEffConst.PLAY_EFF_BULLET or
				effType == LSkillEffConst.PLAY_EFF_DRAWING
		then
			local dp = self:CreateEffect(v, i, onPreloadSkillShow,effType)
			local tempList = preLoadObjList[v.effRes] or {}
			table.insert(tempList, dp)
			preLoadObjList[v.effRes] = tempList
			dp:StartLoad()
		end
	end
end

-----------------------------------------------------------------
function LUISkillCtrl:PlaySkill()
	if self._isDestroy then return end
	if self._isPlaying then return end
	self._isPlaying = true
	self._bFinishCheck = false
	self._startTime = Time.unscaledTime
end

function LUISkillCtrl:CheckPlayList(time)
	--检测没有播放的时间有没有到，到了开始播放
	--已经播放的，检测自己的结束，和子效果的状态

	local playStateList = self._playStateList
	local bFinishAll = true
	local bAniFinished = true
	for k, v in ipairs(self._playEffList) do
		local playState = playStateList[k]
		if not playState.isPlay then
			bFinishAll = false
			if playState.startTime <= time then
				playState.isPlay = true
				playState.endTime = time + playState.playTime
				self:DoPlayEff(v, playState)
			end
			if v.effType == LSkillEffConst.PLAY_EFF_ANI then
				bAniFinished = false
			end
		elseif not playState.isFinished then
			local bChildFinished = playState.childFinished

			if not bChildFinished then
				bChildFinished = self:CheckChildPlayList(playState.childList,time)
			end

			playState.childFinished = bChildFinished

			local bTimeFinished = playState.endTime < time
			if bChildFinished and bTimeFinished then
				playState.isFinished = true
			else
				bFinishAll = false
			end
			if not bTimeFinished and v.effType == LSkillEffConst.PLAY_EFF_ANI then
				bAniFinished = false
			end
		end
	end

	self._isAniFinished = bAniFinished
	return bFinishAll
end

--子弹技能跟随的播放列表
--childList 是通过GenerateChildPlaystate 建的结构
function LUISkillCtrl:CheckChildPlayList(childList, time)
	if not childList or #childList == 0 then
		return true
	end
	local bFinishAll = true
	for m, child in ipairs(childList) do
		if not child.isPlay then
			if child.startTime <= time then
				child.isPlay = true
				self:DoPlayEff(child.effData, child)
			end
		elseif not child.isFinished then
			child.isFinished = child.endTime < time
		end
		if not child.isFinished then
			bFinishAll = false
		end
	end
	return bFinishAll
end

function LUISkillCtrl:DoPlayEff(effData, playState)
	local effType = effData.effType
	if effType == LSkillEffConst.PLAY_EFF_MOVE then

	elseif effType == LSkillEffConst.PLAY_EFF_ANI then
		self:ExecutePlayAni(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_EFFECT then
		self:ExecutePlayEffect(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_BULLET then
		self:ExecutePlayBullet(effData, playState)

	elseif effType == LSkillEffConst.PLAY_EFF_HIT_HUD or effType == LSkillEffConst.PLAY_EFF_HUD then

	elseif effType == LSkillEffConst.PLAY_EFF_SOUND then
		self:ExecutePlaySound(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_SHAKE then

	elseif effType == LSkillEffConst.PLAY_EFF_FADE then

	elseif effType == LSkillEffConst.PLAY_EFF_DRAWING then
		self:ExecutePlayEffect(effData, playState)
	elseif effType == LSkillEffConst.PLAY_EFF_FADE_TOP_EXTRA then
		self:ExecuteTopMaskExtra(effData)
	end

	local soundName = effData.soundBattle
	if not string.isempty(soundName) and self._enableSound then
		gLGameAudio:PlaySound(soundName)
		return
	end
end

