---播放动作
function LUISkillCtrl:ExecutePlayAni(effData,playState)
	local obj = self._uiHeroObj
	--动作名字
	local ani = effData.effRes
	--动作时间
	local time = playState.playTime
	time = effData.actionReset == 0 and time or 0
	obj:PlayAni(ani,false, time)
end

---播放光效
function LUISkillCtrl:ExecutePlayEffect(effData,playState)
	--local effRes = effData.effRes --光效名字
	local playTime = playState.playTime --光效持续时间
	local offset = effData.effOffsetStart --偏移
	local dissipateTime = effData.dissipateTime --光效消散时间

	--local speedUpVal = self._bSpeedUp and self._speedUpVal or nil
	local posList = self:CalcPlayEffectPos(effData)
	for k,v in ipairs(posList) do
		local pos = v.pos
		local offsetX = offset.x * self._pixelPreUnit
		local offsetY = offset.y * self._pixelPreUnit
		pos.x = pos.x + offsetX
		pos.y = pos.y + offsetY
		pos.z = 0
		local effect = self:MakeEffect(effData)
		effect:SetPos(pos)
		effect:StartPlay(self._curTime, playTime + self._curTime + (dissipateTime or 0))
		table.insert(self._uiEffObjList, effect)
	end
end

---播放弹道
function LUISkillCtrl:ExecutePlayBullet(effData, playState)
	local effRes = effData.effRes --光效名字
	local effTarget = effData.effTarget
	local moveSpeed = effData.moveSpeed * 0.01 * self._pixelPreUnit -- 子弹飞行速度(配置表是像素这里要转换成米)
	local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
	local dissipateTime = effData.dissipateTime --光效消散时间
	local offsetStart = effData.effOffsetStart --偏移
	local bulletCdTime = effData.bulletCdTime or 0 --多个子弹的延迟射出间隔
	local playNum = effData.playNum or {} --单个子弹分解次数
	local excursionIObject = effData.excursionIObject or 0
	local curBulletCdTime = 0

	local offsetEnd = effData.effOffsetEnd
	local bulletTarPosList = {}

	local atkPos = Vector3.zero

	local dataList = self:CalcPlayEffectPos(effData,playState)

	local effectPos = Vector3(atkPos.x + offsetStart.x * self._pixelPreUnit, atkPos.y + offsetStart.y * self._pixelPreUnit, 0)

	--子弹都是从自身位置创建，跟自身方向相同
	local moveTimeList = {}
	local maxMoveTime = 0
	local isTarObj = false

	for k, v in ipairs(dataList) do
		local pos = v.pos
		--受击的 和 攻击的朝向相反的
		pos.x = pos.x - offsetEnd.x * self._pixelPreUnit
		if excursionIObject == 1 then
			local randomNum = self._heroOffectPointList[math.random(1,5)]  -- 目标人物偏移值，策划没有设置effOffsetEnd的前提下，0.1-0.3的区间范围：脚底，躯干，头顶
			pos.y = pos.y + (1 - randomNum) * offsetStart.y * self._pixelPreUnit
		else
			pos.y = pos.y + offsetEnd.y * self._pixelPreUnit
		end
		pos.z = 0

		-- 弹道落点列表
		local point = pos:Clone()
		bulletTarPosList[k] = point

		--计算出时间
		local moveTime = (Vector3.Distance(effectPos, pos) / moveSpeed)

		if v.tarId then
			isTarObj = true
		end

		local effect = self:MakeEffect(effData)
		effect:SetPos(effectPos)
		effect:SetBullet(true, pos, moveTime, bulletTrack,k)
		table.insert(self._uiEffObjList, effect)

		effect:StartPlay(self._curTime + curBulletCdTime, moveTime + self._curTime + (dissipateTime or 0) + curBulletCdTime)

		moveTime = moveTime + curBulletCdTime

		if moveTime > maxMoveTime then
			maxMoveTime = moveTime
		end

		table.insert(moveTimeList, moveTime)
		if v.isSingleBulletMuti then
			bulletCdTime = k <= #playNum and playNum[k] or playNum[#playNum]
			-- 单个目标多个子弹的延迟射出间隔
			curBulletCdTime = curBulletCdTime + bulletCdTime
		else
			-- 多个目标的子弹的延迟射出间隔
			curBulletCdTime = curBulletCdTime + bulletCdTime
		end
	end

	local nextPlayList = effData.nextPlayList

	local childList = playState.childList
	if not childList then return end

	--不嵌套子列表
	local startTime = playState.startTime

	local bulletTraPosListLen = #bulletTarPosList
	--计算子播放序列
	if not isTarObj then
		--整体时间轴
		for k, v in ipairs(nextPlayList) do
			local childStartTime = startTime + maxMoveTime + v.delayTime
			local childPlayState = self:GenerateChildPlayState(v, childStartTime, v.playTime, childStartTime + v.playTime)
			table.insert(childList, childPlayState)
		end
	else --单独时间轴 每个目标都不一样的
		for k,v in ipairs(dataList) do
			local moveChildTime = moveTimeList[k]
			for e, childEff in ipairs(nextPlayList) do
				if childEff.effType == LSkillEffConst.PLAY_EFF_ANI or
						childEff.effType == LSkillEffConst.PLAY_EFF_EFFECT or
						childEff.effType == LSkillEffConst.PLAY_EFF_BULLET or
						childEff.effType == LSkillEffConst.PLAY_EFF_SOUND then

					local childStartTime = startTime + moveChildTime + childEff.delayTime
					local childPlayState = self:GenerateChildPlayState(childEff, childStartTime, childEff.playTime, childStartTime + childEff.playTime)
					childPlayState.isSingle = true
					childPlayState.tarId = true

					if bulletTraPosListLen > 0 then
						childPlayState.bulletTarPos = k <= bulletTraPosListLen and bulletTarPosList[k] or bulletTarPosList[bulletTraPosListLen]
					end
					table.insert(childList, childPlayState)
				end
			end
		end
	end
end

---播放声音
function LUISkillCtrl:ExecutePlaySound(effData)
	--声音名字
	local soundName = effData.effRes
	gLGameAudio:PlaySound(soundName)
end

-----------------------------------------------------------------
function LUISkillCtrl:GetSkillEffId()
	return self._skillData._skillEffId
end

------------------------------------------------------------------
function LUISkillCtrl:CalcPlayEffectPos(effData,playState)
	local effTarget = effData.effTarget --目标类型

	if effData.effType == LSkillEffConst.PLAY_EFF_DRAWING then
		return {{pos=Vector3.zero}}
	end

	if effTarget == 1 then
		--1=自身
		return {{pos=Vector3.zero}}
	else
		local dataList = {}
		local originPos = Vector3(1280,0,0)
		local effType = effData.effType
		local playNum = effData.playNum
		if effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
			if playState and playState.isSingle then
				--直接用state中的列表,子弹命中之后发生的表演
				local pos = originPos:Clone()
				table.insert(dataList, {pos=pos})
			else
				--2=每一个目标
				local skillEffId = self:GetSkillEffId()
				local vfxRefId = effData.refId
				local isMultiBullet,vfxIndex = gModelSkill:IsMultiBulletShow(skillEffId,vfxRefId) --多个攻击特效，同一目标多个伤害
				local clientMulti = not table.isempty(playNum) and #playNum > 0  --一个攻击特效，多段伤害飘字表现
				-- 特殊多段子弹类型
				if effType == LSkillEffConst.PLAY_EFF_BULLET and clientMulti then
					table.insert(dataList, {pos=originPos:Clone(), tarId=true, isSingleBulletMuti=true})
					for e, q in ipairs(playNum) do
						table.insert(dataList, {pos=originPos:Clone(), tarId=true, isSingleBulletMuti=true})
					end
				elseif isMultiBullet then --根据伤害次数计算子弹数
					table.insert(dataList, {pos=originPos:Clone(), tarId=true})
				else
					table.insert(dataList, {pos=originPos:Clone(), tarId=true})
				end
			end
		else
			table.insert(dataList, {pos=originPos:Clone()})
		end
		return dataList
	end
end

function LUISkillCtrl:GetFadeObj()
	local fade =self._fade
	if not fade then
		fade = LFightFade:New()
		self._fade = fade
	end

	return fade
end

function LUISkillCtrl:ExecuteTopMaskExtra(effData)
	local fade = self:GetFadeObj()

	local layer = self._wndClass:GetWndSortLayer()
	local order = self._wndClass:GetWndSortOrder()

	local para =
	{
		parentRoot = self._parentTrans,
		startTime = self._curTime,
		playTime = effData.playTime, --光效持续时间
		dissipateTime =effData.dissipateTime, --光效消散时间
		alpha = tonumber(effData.playNum),
		layer = layer,
		order = order + self._fadeSortAdd,
		type = LFightFade.TYPE_THREE,
	}

	fade:Create(para)
end

function LUISkillCtrl:OnFadeRun(time)
	if not self._fade then
		return
	end
	if not self._fade:OnRun(time) then
		self._fade:Destroy()
		self._fade = nil
	end
end

-----------------------------------------------------------------

function LUISkillCtrl:OnRun(time)
	if self._isDestroy then return end
	if not self._isPlaying then return end

	time = time - self._startTime
	self._curTime = time
	if not self._bFinishCheck and self:CheckPlayList(time) then
		self._bFinishCheck = true
	end

	local bAllFinished = true
	for k,v in ipairs(self._uiEffObjList or {}) do
		if v:OnRun(time) then
			bAllFinished = false
		end
	end

	self:OnFadeRun(time)

	if bAllFinished and self._bFinishCheck then
		self._isPlaying = false
		self._isWait = false
	end
end
------------------------------------------------------------------
function LUISkillCtrl:IsDestroy()
	return self._isDestroy
end

function LUISkillCtrl:Destroy()
	if self._isDestroy then return end

	local list = self._uiPreLoadEffList or {}
	for k,tmpList in pairs(list) do
		for _,v in pairs(tmpList) do
			v:Destroy()
		end
		list[k] = nil
	end

	for k,v in pairs(self._uiEffObjList or {}) do
		v:Destroy()
	end

	if self._fade then
		self._fade:Destroy()
	end

	table.removeall(self)

	self._isDestroy = true
end
------------------------------------------------------------------

return LUISkillCtrl